from __future__ import annotations

import base64
from pathlib import Path

HTML_B64 = ""

def main() -> None:
    root = Path.cwd()
    target = root / "app" / "openlayers_map.html"
    target.parent.mkdir(parents=True, exist_ok=True)
    target.write_bytes(base64.b64decode(HTML_B64))
    print(f"[OK] restored {target}")
    print("[DONE] restart the API and hard refresh the browser (Ctrl + F5)")

if __name__ == "__main__":
    main()
